import java.util.*;

public class Solution {
    public static long run(List<String> rows) {
        long hash = 1469598103934665603L;
        int n = rows.size();
        for (int k = 0; k < n; k++) {
            String row = rows.get(k);
            int i = 0;
            while (row.charAt(i) != ':') i++;
            i++;
            int u = 0;
            while (true) {
                char c = row.charAt(i);
                if (c < '0' || c > '9') break;
                u = u * 10 + (c - '0');
                i++;
            }

            while (row.charAt(i) != ':') i++;
            i++;
            int s = 0;
            while (true) {
                char c = row.charAt(i);
                if (c < '0' || c > '9') break;
                s = s * 10 + (c - '0');
                i++;
            }

            while (row.charAt(i) != ':') i++;
            i++;
            boolean f = row.charAt(i) == 't';

            long v = (u & 1023) + s + (f ? 17 : 0);
            hash ^= (v + 1);
            hash *= 1099511628211L;
        }
        return hash;
    }
}
